let str: string = ""

for (let i: number = 0; i < 3; i++) {
  for (let j: number = 0; j < 6; j++) {
    if (j % 3 == 1) {
      str = str + "KA"
    } else if (j % 3 == 0) {
      str = str + "O"
    } else if (j % 3 == 2) {
      str = str + ".TSU"
    } else {
      str = str + "DA."
    }
  }
  str = str + "\n" // quebra a linha
}

console.log(str)
